public class LoanApprover {
    private boolean hasSufficientAge;
    private boolean sufficientIncome;
    private boolean highCreditScore;
    private boolean collateralAvailable;

    public void isEligible(int age, double income, int creditScore, boolean hasCollateral) {
        this.hasSufficientAge = hasSufficientAge(age);
        this.sufficientIncome = sufficientIncome(income);
        this.highCreditScore = highCreditScore(creditScore);
        this.collateralAvailable = collateralAvailable(hasCollateral);

        if (this.hasSufficientAge && this.sufficientIncome && this.highCreditScore && this.collateralAvailable) {
            setEligible(true);
        } else {
            setEligible(false);
        }
    }

    private boolean hasSufficientAge(int age) {
        return age >= 18 && age <= 65;
    }

    private boolean sufficientIncome(double income) {
        return income > 30000;
    }

    private boolean highCreditScore(int creditScore) {
        return creditScore > 650;
    }

    private boolean collateralAvailable(boolean hasCollateral) {
        return hasCollateral;
    }
}

